+
+// Helper to capture stdout
+func captureStdout(t *testing.T, f func() error) (string, error) {
+	t.Helper()
+	old := os.Stdout
+	r, w, _ := os.Pipe()
+	os.Stdout = w
+
+	err := f()
+
+	w.Close()
+	os.Stdout = old
+
+	var buf bytes.Buffer
+	buf.ReadFrom(r)
+	return buf.String(), err
+}
+
+// ====================
+// Test Helper Functions
+// ====================
+
+func TestDetectAgentType(t *testing.T) {
+	tests := []struct {
+		name     string
+		title    string
+		expected string
